mapper.sql:
SELECT EC.SEQ, EC.APPLY_NO, EC.PERSON_ID, EC.APPLY_REASON, EC.AFFIRM_FLAG, TO_CHAR(EC.APPLY_TIME, 'DD-MM-YYYY') APPLY_TIME, get_global_name(EC.AFFIRM_FLAG, #{lang, jdbcType=VARCHAR}) AFFIRM_FLAG_NAME, get_global_name(get_ar_shiftno(EC.PERSON_ID, EC.AR_DATE_STR, #{cpnyId, jdbcType=VARCHAR}), #{lang, jdbcType=VARCHAR}) SHIFT_NAME, EC.ITEM_NO, get_global_name(EC.ITEM_NO, #{lang, jdbcType=VARCHAR}) ITEM_NAME, TO_CHAR(TO_DATE(REPLACE(EC.AR_DATE_STR, '/', '-'), 'YYYY-MM-DD'), 'DD-MM-YYYY') AR_DATE_STR, TO_CHAR(EC.IN_TIME, 'DD-MM-YYYY HH24:MI') IN_TIME, TO_CHAR(EC.OUT_TIME, 'DD-MM-YYYY HH24:MI') OUT_TIME, TO_CHAR(EC.FROM_TIME, 'DD-MM-YYYY HH24:MI') FROM_TIME, TO_CHAR(EC.TO_TIME, 'DD-MM-YYYY HH24:MI') TO_TIME, EC.CONFIRM_FLAG, EC.HR_COMMENT, HR.LOCAL_NAME, HR.EMPID, HR.DEPTNO, get_dept_name(HR.DEPTNO, #{lang, jdbcType=VARCHAR}) DEPT_NAME, HR.POST_GRADE_NO, get_global_name(HR.POST_GRADE_NO, #{lang, jdbcType=VARCHAR}) POST_GRADE_NAME, HR.POST_FAMILY, get_global_name(HR.POST_FAMILY, #{lang, jdbcType=VARCHAR}) POST_FAMILY_NAME, EC.ACTIVITY, GET_UPDATED_INFO(EC.CONFIRM_BY) CONFIRM_BY, GET_AR_TIME_BY_CPNYID(EC.PERSON_ID, EC.AR_DATE_STR, 'IN', #{cpnyId, jdbcType=VARCHAR}) INDOOR_TIME, GET_AR_TIME_BY_CPNYID(EC.PERSON_ID, EC.AR_DATE_STR, 'OUT', #{cpnyId, jdbcType=VARCHAR}) OUTDOOR_TIME FROM ESS_CARD_APPLY_TB EC, HR_EMPLOYEE HR WHERE EC.PERSON_ID = HR.PERSON_ID AND EC.AFFIRM_FLAG = '14014308' AND EC.ACTIVITY = '1' AND HR.PERSON_ID NOT LIKE '111111%' AND EC.CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
AND EC.CONFIRM_FLAG = #{searchConfirmFlag, jdbcType=VARCHAR}
AND EC.CONFIRM_FLAG = '0'
AND (UPPER(HR.EMPID) LIKE '%' || UPPER(#{searchEmpId, jdbcType=VARCHAR}) || '%' OR CONVERTTOUNSIGN(UPPER(HR.LOCAL_NAME)) LIKE '%' || CONVERTTOUNSIGN(UPPER(#{searchEmpId, jdbcType=VARCHAR})) || '%')
AND EC.AR_DATE_STR >= TO_CHAR(TO_DATE(#{fromDate, jdbcType=VARCHAR}, 'YYYY-MM-DD'), 'YYYY/MM/DD')
AND EC.AR_DATE_STR <= TO_CHAR(TO_DATE(#{toDate, jdbcType=VARCHAR}, 'YYYY-MM-DD'), 'YYYY/MM/DD')

mapper.select:
SELECT * FROM (
    SELECT INNER_Q.*, ROWNUM AS RN FROM (

        ORDER BY EC.AR_DATE_STR DESC
    ) INNER_Q
    WHERE ROWNUM <= #{start, jdbcType=INTEGER} + #{length, jdbcType=INTEGER}
) WHERE RN > #{start, jdbcType=INTEGER}

